diff:
diff --git a/middleware/context_timeout.go b/middleware/context_timeout.go
index 6846519..c3af0f6 100644
--- a/middleware/context_timeout.go
+++ b/middleware/context_timeout.go
@@ -62,10 +62,20 @@ func (config ContextTimeoutConfig) ToMiddleware() (echo.MiddlewareFunc, error) {

 			c.SetRequest(c.Request().WithContext(timeoutContext))

-			if err := next(c); err != nil {
-				return config.ErrorHandler(c, err)
+			done := make(chan error, 1)
+			go func() {
+				done <- next(c)
+			}()
+
+			select {
+				case err := <-done:
+					if err != nil {
+						return config.ErrorHandler(c, err)
+					}
+					return nil
+				case <-timeoutContext.Done():
+					return config.ErrorHandler(c, timeoutContext.Err())
 			}
-			return nil
 		}
 	}, nil
 }
